function validateHeadingTags(htmlString) {
	// Split the input string into individual heading elements
	var headingElements = htmlString.split('<');
	// Initialize an empty array to store the valid heading tags
	var validTags = [];
	// Loop over each heading element
	for (var i = 0; i < headingElements.length; i++) {
		// Check if the current element starts with 'h' and contains the end tag
		if (headingElements[i].startsWith('h') && headingElements[i].includes('</')) {
			// Add the valid heading tag to the array
			validTags.push(headingElements[i]);
		}
	}
	// Return the array of valid heading tags
	return validTags;
}

