// Solution
function validateHeadingTags(htmlString) {
	// Remove whitespace from the input string
	var trimmedHtmlString = htmlString.trim();
	// Use a regular expression to match the valid heading tags
	var validTags = trimmedHtmlString.match(/<h[1-6](.*?)</h[1-6]>/g);
	// Return the array of valid heading tags
	return validTags;
}

